import{_ as s,o as a,c as n,a2 as t}from"./chunks/framework.B72_uj9U.js";const f=JSON.parse('{"title":"Aider — Edit Format System (The \\"Tool System\\")","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/aider/tool-system.md","filePath":"research/agents/aider/tool-system.md"}'),o={name:"research/agents/aider/tool-system.md"};function i(l,e,r,p,c,d){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="aider-—-edit-format-system-the-tool-system" tabindex="-1">Aider — Edit Format System (The &quot;Tool System&quot;) <a class="header-anchor" href="#aider-—-edit-format-system-the-tool-system" aria-label="Permalink to &quot;Aider — Edit Format System (The &quot;Tool System&quot;)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Aider doesn&#39;t have a traditional tool system like autonomous agents (no shell execution tool, no file-read tool, no web-search tool). Instead, its <strong>edit formats</strong> serve as the interface between the LLM and the file system. The edit format is the &quot;tool&quot; — it&#39;s the structured protocol through which the LLM expresses code changes.</p><p>This is one of Aider&#39;s most significant contributions to the field. Paul Gauthier&#39;s extensive benchmarking revealed that <strong>the format you ask an LLM to use for code edits dramatically affects both code quality and edit reliability</strong>. A complex format taxes the model&#39;s attention, leaving less capacity for the actual coding task.</p><h2 id="edit-formats" tabindex="-1">Edit Formats <a class="header-anchor" href="#edit-formats" aria-label="Permalink to &quot;Edit Formats&quot;">​</a></h2><h3 id="_1-whole-—-full-file-replacement" tabindex="-1">1. <code>whole</code> — Full File Replacement <a class="header-anchor" href="#_1-whole-—-full-file-replacement" aria-label="Permalink to &quot;1. \`whole\` — Full File Replacement&quot;">​</a></h3><p>The simplest format. The LLM returns the entire updated file inside a fenced code block.</p><p><strong>Format:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>filename.py</span></span>
<span class="line"><span>\`\`\`python</span></span>
<span class="line"><span># entire file content here</span></span>
<span class="line"><span>def greeting(name):</span></span>
<span class="line"><span>    print(&quot;Hello&quot;, name)</span></span>
<span class="line"><span>\`\`\`</span></span></code></pre></div><p><strong>Characteristics:</strong></p><ul><li><strong>Simplest cognitive load</strong> — the LLM just writes code naturally</li><li><strong>Most reliable</strong> — minimal parsing complexity, hard for the LLM to get wrong</li><li><strong>Expensive</strong> — the LLM must re-emit the entire file, even for one-line changes</li><li><strong>Slow</strong> — streaming a large file takes time, especially with slower models</li><li><strong>Best for</strong>: Weaker models (GPT-3.5, small local models), small files</li></ul><p><strong>Used by default for</strong>: GPT-3.5 models, Gemini 2.0 Flash, some smaller models</p><h3 id="_2-diff-—-search-replace-blocks" tabindex="-1">2. <code>diff</code> — Search/Replace Blocks <a class="header-anchor" href="#_2-diff-—-search-replace-blocks" aria-label="Permalink to &quot;2. \`diff\` — Search/Replace Blocks&quot;">​</a></h3><p>The LLM specifies edits as pairs of SEARCH (original) and REPLACE (new) text blocks.</p><p><strong>Format:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>filename.py</span></span>
<span class="line"><span>\`\`\`python</span></span>
<span class="line"><span>&lt;&lt;&lt;&lt;&lt;&lt;&lt; SEARCH</span></span>
<span class="line"><span>from flask import Flask</span></span>
<span class="line"><span>=======</span></span>
<span class="line"><span>import math</span></span>
<span class="line"><span>from flask import Flask</span></span>
<span class="line"><span>&gt;&gt;&gt;&gt;&gt;&gt;&gt; REPLACE</span></span>
<span class="line"><span>\`\`\`</span></span></code></pre></div><p><strong>Characteristics:</strong></p><ul><li><strong>Efficient</strong> — only changed portions are transmitted</li><li><strong>Requires precision</strong> — the SEARCH block must match existing code exactly</li><li><strong>Fuzzy matching fallback</strong> — aider tries progressively looser matching if exact match fails: <ol><li>Exact match</li><li>Strip trailing whitespace</li><li>Ignore blank lines</li><li>Normalized whitespace matching</li></ol></li><li><strong>Multiple blocks per file</strong> — can make several changes in one response</li><li><strong>New files</strong> — an empty SEARCH block signals file creation</li><li><strong>Best for</strong>: Most capable models (Claude, GPT-4, DeepSeek)</li></ul><p><strong>Used by default for</strong>: Claude 3.5/3.7 Sonnet, GPT-4o, GPT-4.1, DeepSeek V3/R1, o3, o3-mini</p><h3 id="_3-diff-fenced-—-fenced-variant-for-gemini" tabindex="-1">3. <code>diff-fenced</code> — Fenced Variant for Gemini <a class="header-anchor" href="#_3-diff-fenced-—-fenced-variant-for-gemini" aria-label="Permalink to &quot;3. \`diff-fenced\` — Fenced Variant for Gemini&quot;">​</a></h3><p>Identical to <code>diff</code> semantically, but the filename is placed <strong>inside</strong> the fence instead of before it.</p><p><strong>Format:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>\`\`\`</span></span>
<span class="line"><span>filename.py</span></span>
<span class="line"><span>&lt;&lt;&lt;&lt;&lt;&lt;&lt; SEARCH</span></span>
<span class="line"><span>from flask import Flask</span></span>
<span class="line"><span>=======</span></span>
<span class="line"><span>import math</span></span>
<span class="line"><span>from flask import Flask</span></span>
<span class="line"><span>&gt;&gt;&gt;&gt;&gt;&gt;&gt; REPLACE</span></span>
<span class="line"><span>\`\`\`</span></span></code></pre></div><p><strong>Why it exists</strong>: Gemini models consistently fail to conform to the standard <code>diff</code> fencing approach (placing the filename outside the fence). This variant was created specifically because Gemini would put the filename inside regardless of instructions. Rather than fight the model, aider adapted the format.</p><p><strong>Used by default for</strong>: All Gemini 2.5 Pro and Flash models</p><h3 id="_4-udiff-—-unified-diff-format" tabindex="-1">4. <code>udiff</code> — Unified Diff Format <a class="header-anchor" href="#_4-udiff-—-unified-diff-format" aria-label="Permalink to &quot;4. \`udiff\` — Unified Diff Format&quot;">​</a></h3><p>Based on the standard unified diff format, simplified for LLM use.</p><p><strong>Format:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>\`\`\`diff</span></span>
<span class="line"><span>--- filename.py</span></span>
<span class="line"><span>+++ filename.py</span></span>
<span class="line"><span>@@ ... @@</span></span>
<span class="line"><span>-class MathWeb:</span></span>
<span class="line"><span>+import sympy</span></span>
<span class="line"><span>+</span></span>
<span class="line"><span>+class MathWeb:</span></span>
<span class="line"><span>\`\`\`</span></span></code></pre></div><p><strong>Characteristics:</strong></p><ul><li><strong>Familiar format</strong> — based on universal diff syntax</li><li><strong>Reduced lazy coding</strong> — specifically designed to combat GPT-4 Turbo&#39;s tendency to elide code with &quot;# ... rest of code here ...&quot; comments</li><li><strong>Fragile line numbers</strong> — LLMs sometimes get line numbers wrong in <code>@@</code> headers</li><li><strong>Best for</strong>: GPT-4 Turbo models specifically</li></ul><p><strong>Historical note</strong>: This format was a targeted fix for GPT-4 Turbo&#39;s laziness problem and is less commonly used today.</p><h3 id="_5-architect-—-two-model-pipeline" tabindex="-1">5. <code>architect</code> — Two-Model Pipeline <a class="header-anchor" href="#_5-architect-—-two-model-pipeline" aria-label="Permalink to &quot;5. \`architect\` — Two-Model Pipeline&quot;">​</a></h3><p>Not really an edit format itself, but a <strong>meta-mode</strong> that chains two models.</p><p><strong>How it works:</strong></p><ol><li>The <strong>architect model</strong> receives the user&#39;s request and describes the solution in plain text</li><li>The <strong>editor model</strong> receives the architect&#39;s description and produces structured edits (using <code>editor-diff</code> or <code>editor-whole</code> sub-formats)</li></ol><p><strong>Architect prompt</strong> (simplified):</p><blockquote><p>&quot;Describe how to solve this coding problem. Don&#39;t write code edits — just explain what needs to change.&quot;</p></blockquote><p><strong>Editor prompt</strong> (simplified):</p><blockquote><p>&quot;The architect has described these changes. Now produce the specific file edits using SEARCH/REPLACE blocks.&quot;</p></blockquote><p><strong>Sub-formats:</strong></p><ul><li><code>editor-diff</code> — Streamlined diff format with simpler prompts focused solely on edit mechanics</li><li><code>editor-whole</code> — Streamlined whole-file format for the editor</li></ul><p><strong>Characteristics:</strong></p><ul><li><strong>Separation of concerns</strong> — reasoning model reasons, editing model edits</li><li><strong>SOTA results</strong> — o1-preview + DeepSeek/o1-mini achieved 85% (the original SOTA)</li><li><strong>Higher cost</strong> — two LLM calls per turn</li><li><strong>Higher latency</strong> — sequential model calls</li><li><strong>Best for</strong>: Reasoning models (o1, o3, R1) that struggle with structured edit output</li></ul><p><strong>Key configurations:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># o3 as architect, GPT-4.1 as editor</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">aider</span><span style="color:#A6E3A1;"> --model</span><span style="color:#A6E3A1;"> o3</span><span style="color:#A6E3A1;"> --architect</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># DeepSeek R1 as architect, Claude Sonnet as editor</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">aider</span><span style="color:#A6E3A1;"> --architect</span><span style="color:#A6E3A1;"> --model</span><span style="color:#A6E3A1;"> r1</span><span style="color:#A6E3A1;"> --editor-model</span><span style="color:#A6E3A1;"> sonnet</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Same model as both architect and editor (still helps!)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">aider</span><span style="color:#A6E3A1;"> --model</span><span style="color:#A6E3A1;"> sonnet</span><span style="color:#A6E3A1;"> --architect</span></span></code></pre></div><h3 id="_6-whole-func-and-diff-func-—-function-call-variants" tabindex="-1">6. <code>whole-func</code> and <code>diff-func</code> — Function Call Variants <a class="header-anchor" href="#_6-whole-func-and-diff-func-—-function-call-variants" aria-label="Permalink to &quot;6. \`whole-func\` and \`diff-func\` — Function Call Variants&quot;">​</a></h3><p>Early experiments using OpenAI&#39;s function calling API to structure edits as JSON.</p><p><strong>Outcome</strong>: Benchmarking showed these performed <strong>worse</strong> than plain text formats. The additional cognitive overhead of producing valid JSON hurt both code quality and format adherence. These are historical artifacts, rarely used today.</p><h2 id="the-prompts" tabindex="-1">The Prompts <a class="header-anchor" href="#the-prompts" aria-label="Permalink to &quot;The Prompts&quot;">​</a></h2><p>Each edit format has a carefully crafted system prompt. These are in <code>aider/coders/*_prompts.py</code>:</p><ul><li><code>editblock_prompts.py</code> — diff format instructions</li><li><code>wholefile_prompts.py</code> — whole format instructions</li><li><code>udiff_prompts.py</code> — unified diff instructions</li><li><code>editor_editblock_prompts.py</code> — editor-diff for architect mode</li><li><code>editor_whole_prompts.py</code> — editor-whole for architect mode</li></ul><p>The prompts are <strong>extensively tuned</strong> through benchmark iteration. Small changes to wording can move benchmark scores by several percentage points. Key prompt engineering insights:</p><ol><li><strong>Concrete examples</strong> — Each prompt includes worked examples of the format</li><li><strong>Explicit rules</strong> — &quot;Every SEARCH block must exactly match existing file content&quot;</li><li><strong>Common mistakes</strong> — Prompts explicitly warn against known failure modes</li><li><strong>Minimal complexity</strong> — Simpler prompts → better code (the benchmark proved this)</li></ol><h2 id="edit-format-selection-logic" tabindex="-1">Edit Format Selection Logic <a class="header-anchor" href="#edit-format-selection-logic" aria-label="Permalink to &quot;Edit Format Selection Logic&quot;">​</a></h2><p>Aider automatically selects the best edit format per model:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Model                          → Default Format</span></span>
<span class="line"><span>─────────────────────────────────────────────</span></span>
<span class="line"><span>GPT-5                          → diff</span></span>
<span class="line"><span>GPT-4.1                        → diff</span></span>
<span class="line"><span>GPT-4o                         → diff</span></span>
<span class="line"><span>GPT-3.5 Turbo                  → whole</span></span>
<span class="line"><span>o3, o3-pro                     → diff</span></span>
<span class="line"><span>o1                             → diff (architect recommended)</span></span>
<span class="line"><span>Claude 3.5/3.7 Sonnet          → diff</span></span>
<span class="line"><span>Claude Opus                    → diff</span></span>
<span class="line"><span>Gemini 2.5 Pro                 → diff-fenced</span></span>
<span class="line"><span>Gemini 2.5 Flash               → diff-fenced</span></span>
<span class="line"><span>DeepSeek V3, R1                → diff</span></span>
<span class="line"><span>Local models (Ollama)          → whole (usually safest)</span></span></code></pre></div><p>Users can override with <code>--edit-format &lt;format&gt;</code>.</p><h2 id="the-key-insight" tabindex="-1">The Key Insight <a class="header-anchor" href="#the-key-insight" aria-label="Permalink to &quot;The Key Insight&quot;">​</a></h2><p>Aider&#39;s benchmark data reveals a profound finding about LLM tool use:</p><blockquote><p><strong>The simpler the output format, the better the LLM&#39;s actual coding performance.</strong></p></blockquote><p>This has implications far beyond Aider. It suggests that autonomous agent frameworks should minimize the syntactic overhead of tool calls. When an LLM spends attention on formatting, it has less attention for reasoning.</p><p>The function-call formats (<code>whole-func</code>, <code>diff-func</code>) were expected to be more reliable (that was the whole point of OpenAI&#39;s function calling API), but they actually performed worse. Plain text with simple delimiters beat structured JSON every time.</p><p>This finding was instrumental in shaping how the industry thinks about LLM tool interfaces.</p>`,64)])])}const m=s(o,[["render",i]]);export{f as __pageData,m as default};
